INSERT INTO `job_postings` VALUES (1,1,4,'AI Engineer','About the Role\nWe are seeking a detail-oriented and passionate Lead IoT & Embedded Systems Engineer to drive our hardware-software integration and real-time automation initiatives. The ideal candidate will have a strong foundation in Electronics and Communication Engineering, coupled with hands-on experience in edge computing, sensor interfacing, and wireless communication. You will lead innovative hardware-driven projects, bridging the gap between physical sensors, Edge AI, and robust backend infrastructure.\n\nKey Responsibilities\nLead and execute Edge AI projects, including image recognition, video surveillance, and AI-based inventory management systems.\n\nDesign, develop, and deploy IoT and embedded solutions using NVIDIA Jetson Boards, Raspberry Pi, NodeMCU, and Arduino microcontrollers.\n\nInterface sensors and actuators for real-time automation and hardware-software integration.\n\nManage and monitor server infrastructure, utilizing Docker, Redis, and relational databases (MySQL, SQLite) to ensure seamless system integration.\n\nHandle networking configurations, troubleshoot VPN connectivity, and manage MPLS and BGP protocols.\n\nDevelop and maintain supplementary backend and internal applications using Java, PHP, and HTML.\n\nAct as the primary technical point of contact for complex hardware integration and system monitoring projects.\n\nRequired Qualifications\nB.Tech/B.E. in Electronics and Communication Engineering (ECE) or a closely related field.\n\n3 to 5 years of professional experience in IoT, Embedded Systems, or Edge AI development.\n\nStrong programming proficiency in Java, PHP, and SQL, along with hardware-level C/C++ for microcontrollers.\n\nProven hands-on experience with hardware platforms like NVIDIA Jetson, Raspberry Pi, and general microprocessors.\n\nFamiliarity with networking (MPLS, BGP) and infrastructure monitoring tools.\n\nExperience utilizing development tools such as VS Code, NetBeans, and cPanel.\n\nNice to Have\nAn Executive MBA or equivalent business acumen to assist with cross-functional leadership and team collaboration.\n\nA strong portfolio of personal IoT and automation projects (e.g., smart home automation, real-time tracking devices, or health monitoring systems).\n\nPrevious experience managing intelligent traffic systems or large-scale hardware deployments.','Python, Node.js, Next.js, Express.js, PHP, DevOPS','Hyderabad,India','full_time','hybrid',500000.00,600000.00,3.0,5.0,'active',1,1,'2026-05-31','2026-05-09 14:41:02','2026-05-14 20:15:24',NULL),(2,1,4,'Marketing Executive','Role Overview\nWe are looking for a results-driven Marketing Executive to build and execute Ladder Consulting\'s brand presence, generate qualified leads for our recruitment and HR services, and support business development efforts across B2B and B2C channels.\n\nKey Responsibilities\nPlan and execute digital marketing campaigns across LinkedIn, Instagram, Google, and other relevant platforms to promote Ladder Consulting\'s HR, recruitment, and training services\n\nGenerate and nurture B2B leads from companies looking for recruitment and HR outsourcing solutions\n\nCreate and manage content — including blogs, case studies, LinkedIn posts, emailers, and creatives — aligned with employer branding and service offerings\n\nDrive candidate acquisition campaigns to grow the talent database for recruitment placements\n\nManage SEO/SEM initiatives to increase organic visibility and inbound inquiries\n\nCoordinate with the sales and HR teams to align marketing campaigns with active job requirements and client mandates\n\nTrack and report campaign performance metrics (CPL, CTR, conversion rates) and optimize regularly\n\nBuild and manage relationships with colleges, training institutes, and industry communities for brand partnerships\n\nRepresent Ladder Consulting at career fairs, networking events, and industry conferences\n\nMaintain and update the company website, landing pages, and branding collateral\n\nRequired Skills & Qualifications\nBachelor\'s degree in Marketing, Business Administration, Mass Communication, or a related field\n\n1–3 years of experience in B2B/B2C marketing (experience in HR, staffing, or SaaS is a plus)\n\nProficiency in digital marketing tools — Google Ads, Meta Ads Manager, LinkedIn Campaign Manager\n\nStrong written and verbal communication skills in English and Telugu/Hindi\n\nHands-on experience with Canva, Adobe Suite, or similar design tools for content creation\n\nWorking knowledge of CRM tools, email marketing platforms (Mailchimp, Brevo), and analytics tools (Google Analytics)\n\nAbility to work independently, manage multiple campaigns, and meet deadlines\n\nGood to Have\nExperience marketing HR tech platforms, recruitment services, or staffing agencies\n\nUnderstanding of WhatsApp-based marketing campaigns and automation\n\nKnowledge of employer branding strategies and LinkedIn organic growth\n\nWhat We Offer\nCompetitive salary with performance-based incentives\n\nExposure to a growing HR tech ecosystem and recruitment SaaS platform\n\nOpportunity to build and own the marketing function from the ground up\n\nDynamic and collaborative work environment in Hyderabad','Excellent communication and networking.\n\nLead generation and business development.\n\nDigital marketing across LinkedIn, Google, Meta, and email.\n\nContent writing, copywriting, and basic design.\n\nSEO, campaign planning, and performance tracking.\n\nStrong organization, multitasking, and time management.\n\nCommercial awareness and client-focused thinking.\n\nReporting and analytical skills to measure campaign results.\n\nTeam coordination with HR and sales.\n\nAdaptability and creativity.','Hyderabad, India','full_time','onsite',200000.00,300000.00,2.0,5.0,'active',1,1,'2026-05-31','2026-05-19 05:30:45','2026-05-19 05:30:45',NULL),(3,2,33,'FInance & Accounts','Maintain accurate books of accounts using Tally, Zoho Books, or similar accounting software\n\nRecord and reconcile daily transactions including invoices, receipts, payments, and expenses\n\nManage accounts payable and receivable, and follow up on outstanding client payments\n\nPrepare and file GST returns (GSTR-1, GSTR-3B), TDS, and other statutory filings on time\n\nHandle payroll processing for internal employees — salary computation, PF, ESI, and PT deductions\n\nAssist in preparing monthly, quarterly, and annual financial statements and MIS reports\n\nCoordinate with consultants, vendors, and clients for billing and invoice queries\n\nSupport the management with budgeting, forecasting, and cash flow monitoring\n\nMaintain records of recruitment placements and training invoices with client-wise tracking\n\nLiaise with CA/auditors during internal and statutory audits\n\nEnsure compliance with company financial policies and applicable tax regulations','Bachelor\'s degree in Commerce (B.Com) or equivalent; M.Com or CA Inter preferred\n\n1–4 years of hands-on experience in accounting or finance roles\n\nProficiency in Tally ERP, Zoho Books, or similar accounting software\n\nStrong working knowledge of GST, TDS, income tax, and payroll compliance\n\nCompetent in MS Excel — pivot tables, VLOOKUP, and financial reports\n\nGood attention to detail, organized, and capable of managing deadlines\n\nStrong communication skills in English and Telugu/Hindi for client and vendor coordination\n\nUnderstanding of service-sector billing and invoicing practices','Hyderabad, Telangana','full_time','onsite',25000.00,30000.00,1.0,3.0,'active',1,1,'2026-06-30','2026-06-15 11:11:18','2026-06-15 11:11:18',NULL),(4,4,46,'Test Role','Verification job posting',NULL,'Remote','full_time','remote',NULL,NULL,0.0,NULL,'closed',0,1,NULL,'2026-06-29 16:39:20','2026-06-29 16:40:25','2026-06-29 22:10:25'),(5,4,46,'Fee Test Role','Verification job',NULL,'Remote','full_time','remote',NULL,NULL,0.0,NULL,'active',0,1,NULL,'2026-06-29 17:37:36','2026-06-29 17:37:36',NULL);
