LOCK TABLES `resumes` WRITE;
/*!40000 ALTER TABLE `resumes` DISABLE KEYS */;
INSERT INTO `resumes` VALUES (1,1,'uploads/resumes/resume_1_1778761665837.pdf','Nachiketh_Desai_Resume.pdf',64063,'application/pdf','\n\nNachiketh	M	Desai	\nDate	of	Birth:	25	April	2000	|	Contact:	+91-8686903927	|	Email:	nachiketh.2504@gmail.com	\n	\nObjective	\nA	passionate	and	detail-oriented	Electronics	and	Communication	Engineer	with	a	strong	focus	\non	Embedded	Systems,	IoT,	and	hardware	integration.	Experienced	in	developing	real-time	\nautomation	solutions	using	microcontrollers,	NVIDIA	Jetson	Boards,	Raspberry	Pi,	and	\nactuator-based	systems.	Skilled	in	wireless	communication,	sensor	interfacing,	and	embedded	\nhardware-software	integration.	Looking	to	contribute	to	innovative,	software	and	hardware-\ndriven	projects.	\n	\nWork	Experience	\nIoT	Lead	-	Cognolabs	Systems	Private	Limited	|	MAY	2025	-	Present	\n•	Leading	Edge	AI	projects	including	image	recognition,	video	surveillance,	and	AI-based	\ninventory	systems.	\nDevOps	Engineer	Trainee	-	ITS	Planners	&	Engineers	Pvt	Ltd	|	FEB	2025	-	APR	2025	\n•	Managed	Raspberry	Pi-based	traf[ic	signal	systems	and	large-scale	HTMS	projects.	\n•	Monitored	servers	across	India,	used	Docker,	Redis,	and	databases	for	system	integration.	\nL2	-	Project	Engineer	-	Wipro	Limited	|	NOV	2021	-	AUG	2024	\n•	Generated	MPLS	con[igurations,	managed	VPN	connectivity,	and	was	promoted	as	SPOC	for	\nAPAC	and	RAM	regions.	\nResearch	Intern	-	Administrative	Staff	College	of	India	|	DEC	2019	\n•	Contributed	to	EV	policy	enhancement	project	in	Tel a nga na .	\nSummer	Intern	-	ECIL	|	JUN	2019	\n•	Built	an	IoT-based	Home	Security	System	for	intrusion	detection.	\n	\nAcademic	QualiXications	\n•	Executive	MBA,	ICFAI	Business	School,	Hyderabad	|	2023	-	2025	|	Grade:	83.3%	\n•	B.Tech	in	ECE,	SRM	IST,	Chennai	|	2017	-	2021	|	Grade:	72.06%	\n•	Class	XII,	BSRKV,	Hyderabad	|	2015	-	2017	|	Grade:	63%	\n•	Class	X,	BSRKV,	Hyderabad	|	2005	-	2015	|	CGPA:	8.8	\n\n	\nTechnical	Skills	\n•	Programming:	Java,	PHP,	HTML,	MySQL	\n•	Embedded	&	IoT:	NVIDIA	Jetson,	Raspberry	Pi,	NodeMCU,	Sensor	&	Actuator	Interfacing	\n•	Databases:	SQLite,	MySQL	\n•	Tool s:	NetBeans,	VS	Code,	Docker,	Redis,	cPanel	\n•	Networking:	MPLS,	BGP	\n•	Microcontrollers:	Arduino,	General	Microprocessors	\n	\nSoft	Skills	\n•	Research	&	Analytical	Thinking	\n•	Creative	Problem	Solving	\n•	Communication	&	Interpersonal	Skills	\n•	Tea m	Collaboration	&	Leadership	\n	\nPersonal	Projects	\n•	Women’s	Safety	Device	-	Real-time	emergency	location	alerts.	\n•	Touch-less	Sanitiser	Dispenser	-	IR-based,	non-contact	sanitiser	system.	\n•	Oximeter	-	Measures	SpO2	and	pulse	rate	using	LEDs	and	photodiode.	\n•	Home	Automation	-	NodeMCU	&	Blynk-based	control	of	appliances.	\n•	E-Bicycle	-	IoT-based	tracking,	theft	detection,	and	remote	lock/unlock.	\n•	Billing	App	-	Java	+	MySQL	billing	system	for	pharmacies.	\n•	Daily	Reporting	Portal	-	PHP-based	employee	reporting	system.	\n•	HRMS	Portal	-	Java-based	payroll	and	payslip	generation	system.	\n	\nPersonal	Information	\nHobbies:	Travelling,	Cooking,	Playing	Guitar,	Solving	puzzles	(e.g.,	Rubik’s	cube)	\nLanguages	Known:	English,	Hindi,	Tel u gu ,	Marathi','done',0,'2026-05-14 12:27:47','2026-05-14 20:35:21',NULL),(2,1,'uploads/resumes/resume_1_1778790921111.pdf','Nachiketh_Desai_Resume.pdf',64063,'application/pdf','\n\nNachiketh	M	Desai	\nDate	of	Birth:	25	April	2000	|	Contact:	[PHONE REDACTED]	|	Email:	[EMAIL REDACTED]	\n	\nObjective	\nA	passionate	and	detail-oriented	Electronics	and	Communication	Engineer	with	a	strong	focus	\non	Embedded	Systems,	IoT,	and	hardware	integration.	Experienced	in	developing	real-time	\nautomation	solutions	using	microcontrollers,	NVIDIA	Jetson	Boards,	Raspberry	Pi,	and	\nactuator-based	systems.	Skilled	in	wireless	communication,	sensor	interfacing,	and	embedded	\nhardware-software	integration.	Looking	to	contribute	to	innovative,	software	and	hardware-\ndriven	projects.	\n	\nWork	Experience	\nIoT	Lead	-	Cognolabs	Systems	Private	Limited	|	MAY	2025	-	Present	\n•	Leading	Edge	AI	projects